     |   ^^^^^^^^^^^^^

Found 1 error.
```
```
@doc("Stage Properties")
model StageSpec {
  @doc("Name of Stage")
  name: string;

  @removed(Versions.v2025_06_01_preview)
  @doc("Target ARM id")
